diff --git a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
index c07af8519049..4bfcef4b1267 100644
--- a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
+++ b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
@@ -7423,7 +7423,6 @@ static bool planContainsAdditionalSimplifications(VPlan &Plan,
       return &WidenMem->getIngredient();
     return nullptr;
   };
-
   DenseSet<Instruction *> SeenInstrs;
   auto Iter = vp_depth_first_deep(Plan.getVectorLoopRegion()->getEntry());
   for (VPBasicBlock *VPBB : VPBlockUtils::blocksOnly<VPBasicBlock>(Iter)) {
@@ -7431,21 +7430,17 @@ static bool planContainsAdditionalSimplifications(VPlan &Plan,
       if (auto *IR = dyn_cast<VPInterleaveRecipe>(&R)) {
         auto *IG = IR->getInterleaveGroup();
         unsigned NumMembers = IG->getNumMembers();
-        for (unsigned I = 0; I != NumMembers; ++I) {
+        for (unsigned I = 0; I != NumMembers; ++I)
           if (Instruction *M = IG->getMember(I))
             SeenInstrs.insert(M);
-        }
         continue;
       }
       if (Instruction *UI = GetInstructionForCost(&R))
         SeenInstrs.insert(UI);
     }
   }
-
-  // Return true if the loop contains any instructions that are not also part of
-  // the VPlan or are skipped for VPlan-based cost computations. This indicates
-  // that the VPlan contains extra simplifications.
-  return any_of(TheLoop->blocks(), [&SeenInstrs, &CostCtx,
+  // Instructions not represented in the VPlan (and not skipped) indicate extra simplifications.
+  bool ExtraSimplifications = any_of(TheLoop->blocks(), [&SeenInstrs, &CostCtx,
                                     TheLoop](BasicBlock *BB) {
     return any_of(*BB, [&SeenInstrs, &CostCtx, TheLoop, BB](Instruction &I) {
       if (isa<PHINode>(&I) && BB == TheLoop->getHeader())
@@ -7453,6 +7448,28 @@ static bool planContainsAdditionalSimplifications(VPlan &Plan,
       return !SeenInstrs.contains(&I) && !CostCtx.skipCostComputation(&I, true);
     });
   });
+  if (ExtraSimplifications)
+    return true;
+  // Additional heuristic: select with loop-invariant condition treated as simplification.
+  for (BasicBlock *BB : TheLoop->blocks()) {
+    for (Instruction &I : *BB) {
+      if (auto *SI = dyn_cast<SelectInst>(&I)) {
+        if (TheLoop->isLoopInvariant(SI->getOperand(0)))
+          return true;
+          // Heuristic extension: if the select condition is an instruction
+          // (e.g. an icmp) whose operands are all loop-invariant, treat it
+          // as an additional simplification (uniform predicate usage).
+          if (auto *CondI = dyn_cast<Instruction>(SI->getOperand(0))) {
+            bool AllInv = true;
+            for (Value *Op : CondI->operands())
+              if (!TheLoop->isLoopInvariant(Op)) { AllInv = false; break; }
+            if (AllInv)
+              return true;
+          }
+      }
+    }
+  }
+  return false;
 }
 #endif

