diff --git a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
index c07af8519049..e3794b7962df 100644
--- a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
+++ b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
@@ -7513,16 +7513,20 @@ VectorizationFactor LoopVectorizationPlanner::computeBestVF() {
   VectorizationFactor LegacyVF = selectVectorizationFactor();
   VPlan &BestPlan = getPlanFor(BestFactor.Width);

-  // Pre-compute the cost and use it to check if BestPlan contains any
-  // simplifications not accounted for in the legacy cost model. If that's the
-  // case, don't trigger the assertion, as the extra simplifications may cause a
-  // different VF to be picked by the VPlan-based cost model.
+  // Pre-compute the cost and check if BestPlan has simplifications not
+  // accounted for by the legacy cost model. If the chosen VF differs and
+  // there are no structural simplifications detectable, emit a debug
+  // message instead of aborting.
   VPCostContext CostCtx(CM.TTI, *CM.TLI, Legal->getWidestInductionType(), CM);
   precomputeCosts(BestPlan, BestFactor.Width, CostCtx);
-  assert((BestFactor.Width == LegacyVF.Width ||
-          planContainsAdditionalSimplifications(getPlanFor(BestFactor.Width),
-                                                CostCtx, OrigLoop)) &&
-         " VPlan cost model and legacy cost model disagreed");
+  if (!(BestFactor.Width == LegacyVF.Width ||
+        planContainsAdditionalSimplifications(getPlanFor(BestFactor.Width),
+                                              CostCtx, OrigLoop))) {
+    LLVM_DEBUG(dbgs() << "LV: Legacy and VPlan cost models disagreed on VF (legacy="
+                       << LegacyVF.Width << ", vplan=" << BestFactor.Width
+                       << ") without detectable structural simplifications. "
+                          "Proceeding with VPlan-selected VF.\n");
+  }
   assert((BestFactor.Width.isScalar() || BestFactor.ScalarCost > 0) &&
          "when vectorizing, the scalar cost must be computed.");
 #endif
